class HTTPError extends Error {
  constructor(status, statusText, responseBody) {
    super(`HTTP Error: ${status} ${statusText}`);
    this.name = 'HTTPError';
    this.status = status; // e.g., 404, 500
    this.statusText = statusText; // e.g., "Not Found"
    this.responseBody = responseBody; // Parsed JSON or raw text error body
  }
}

class NetworkError extends Error {
  constructor(cause) {
    super('Network request failed (check internet/CORS)');
    this.name = 'NetworkError';
    this.cause = cause; // Original error for debugging
  }
}

class ParseError extends Error {
  constructor(cause, responseText) {
    super('Failed to parse response as JSON');
    this.name = 'ParseError';
    this.cause = cause; // Original SyntaxError
    this.responseText = responseText; // Raw response for debugging
