/**
 * Fetches a user by ID
 * @param {string|number} id - User ID (non-null string/number)
 * @param {object} [options={}]
 * @param {AbortSignal} [options.signal] - Signal to cancel the request
 * @param {number} [options.timeout=10000] - Request timeout in ms (default: 10s)
 * @returns {Promise<object>} Parsed JSON user object
 * @throws {TypeError|NetworkError|HTTPError|ParseError}
 */
async function getUser(id, { signal, timeout = 10000 } = {}) {
  // ------------------------------
  // 1. Input Validation (Early Failure)
  // ------------------------------
  // Basic type validation
  if (id == null || (typeof id !== 'string' && typeof id !== 'number')) {
    throw new TypeError('User ID must be a non-null string or number');
  }

  const idStr = String(id).trim();
  if (!idStr) throw new TypeError('User ID cannot be empty');

  // Block path separators to prevent traversal (extra security layer)
  if (idStr.includes('/') || idStr.includes('\\')) {
    throw new TypeError('User ID cannot contain path separators');
  }

  // Optional: Add format validation for your ID type (e.g., UUID, numeric)
  // Example for numeric IDs: if (!/^\d+$/.test(idStr)) throw new TypeError('User ID must be numeric');
  // Example for UUID v4: if (!/^[0-9a-f-]{36}$/i.test(idStr)) throw new TypeError('Invalid UUID');

  // ------------------------------
  // 2. Safe URL Construction
  // ------------------------------
  const baseUrl = window.location.origin; // Replace with API base for cross-origin (e.g., "https://api.example.com")
  // Encode ID to escape reserved characters (prevents broken URLs/partial traversal)
  const url = new URL(`/api/users/${encodeURIComponent(idStr)}`, baseUrl);

  // ------------------------------
  // 3. Abort Controller (Timeout + Cancellation)
  // ------------------------------
  const abortController = new AbortController();
  // Set timeout to prevent hanging requests
  const timeoutId = setTimeout(
    () => abortController.abort(new Error('Request timed out')),
    timeout
  );
  // Link caller's abort signal (if provided)
  if (signal) {
    signal.addEventListener('abort', () => {
      clearTimeout(timeoutId);
      abortController.abort(signal.reason);
    }, { once: true });
  }

  try {
    // ------------------------------
    // 4. Secure Fetch Configuration
    // ------------------------------
    const response = await fetch(url.href, {
      method: 'GET',
      signal: abortController.signal,
      headers: {
        Accept: 'application/json', // Explicitly request JSON
        // Uncomment for CSRF protection (cookie-based auth)
        // 'X-CSRF-Token': document.querySelector('meta[name="csrf-token"]')?.content,
        // Uncomment for Bearer token auth
        // 'Authorization': `Bearer ${localStorage.getItem('jwt')}`
      },
      // Uncomment for cross-origin requests requiring cookies
